package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetAllowMissingColumnNames_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getAllowMissingColumnNames(), "DEFAULT should not allow missing column names");
    }

    @Test
    public void testGetAllowMissingColumnNames_WithAllowMissingColumnNames() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames();
        assertTrue(format.getAllowMissingColumnNames(), "Format withAllowMissingColumnNames should allow missing column names");
    }

    @Test
    public void testGetAllowMissingColumnNames_WithAllowMissingColumnNamesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames(), "Format withAllowMissingColumnNames(false) should not allow missing column names");
    }

    @Test
    public void testGetAllowMissingColumnNames_Immutable() {
        CSVFormat format1 = CSVFormat.DEFAULT;
        CSVFormat format2 = format1.withAllowMissingColumnNames();
        CSVFormat format3 = format2.withAllowMissingColumnNames(false);

        assertFalse(format1.getAllowMissingColumnNames(), "Original format should remain unchanged");
        assertTrue(format2.getAllowMissingColumnNames(), "Modified format2 should allow missing column names");
        assertFalse(format3.getAllowMissingColumnNames(), "Modified format3 should not allow missing column names");
    }
}
